-- 3. PROVEEDORES_OFICIALES (150 registros - muestro 50)
-- =====================================================

-- =====================================================
-- 4. SUCURSALES_OFICIALES (200 registros - muestro 30)
-- =====================================================

-- =====================================================
-- 5. METAS_ABASTECIMIENTO (200 registros)
-- =====================================================
SELECT 
    p.id_proveedor,
    s.id_sucursal,
    2024,
    m.mes,
    1000 + (FLOOR(RANDOM() * 4000)),
    10 + FLOOR(RANDOM() * 20),
    3.5 + RANDOM() * 1.5,
    70 + RANDOM() * 30,
    80 + RANDOM() * 20
FROM 
    (SELECT id_proveedor FROM proveedores_oficiales WHERE estado = 'Activo' LIMIT 15) p
    CROSS JOIN
    (SELECT id_sucursal FROM sucursales_oficiales LIMIT 5) s
    CROSS JOIN
    (SELECT generate_series(1, 12) AS mes) m
WHERE RANDOM() < 0.3
LIMIT 200;

-- =====================================================
-- 6. EVALUACIONES_CALIDAD (200 registros)
-- =====================================================
SELECT
    p.id_proveedor,
    s.id_sucursal,
    CURRENT_DATE - (FLOOR(RANDOM() * 180) || ' days')::INTERVAL,
    1 + FLOOR(RANDOM() * 5),
    RANDOM() > 0.2,
    RANDOM() > 0.15,
    1 + FLOOR(RANDOM() * 5),
    1 + FLOOR(RANDOM() * 5),
    1 + FLOOR(RANDOM() * 5),
    CASE WHEN RANDOM() < 0.2 THEN 'Requiere seguimiento' ELSE 'Cumple estándares' END,
    CASE WHEN RANDOM() < 0.5 THEN 'Supervisor' ELSE 'Gerente de calidad' END
FROM
    (SELECT id_proveedor FROM proveedores_oficiales WHERE estado = 'Activo') p
    CROSS JOIN
    (SELECT id_sucursal FROM sucursales_oficiales) s
WHERE RANDOM() < 0.4
LIMIT 200;